# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

properties([
    parameters([
        string(name: 'BUILD_COMMAND', defaultValue: 'echo "No build command specified"', description: 'Custom build command to execute'),
        string(name: 'TEST_COMMAND', defaultValue: 'echo "No test command specified"', description: 'Custom test command to execute'),
        string(name: 'DEPLOYMENT_COMMAND', defaultValue: 'echo "No deployment command specified"', description: 'Custom deployment command to execute'),
        text(name: 'PRE_BUILD_SCRIPT', defaultValue: '', description: 'Multi-line script to run before build'),
        text(name: 'POST_BUILD_SCRIPT', defaultValue: '', description: 'Multi-line script to run after build'),
        text(name: 'PRE_TEST_SCRIPT', defaultValue: '', description: 'Multi-line script to run before tests'),
        text(name: 'POST_TEST_SCRIPT', defaultValue: '', description: 'Multi-line script to run after tests'),
        text(name: 'PRE_DEPLOY_SCRIPT', defaultValue: '', description: 'Multi-line script to run before deployment'),
        text(name: 'POST_DEPLOY_SCRIPT', defaultValue: '', description: 'Multi-line script to run after deployment'),
        choice(name: 'SHELL_TYPE', choices: ['sh', 'bash', 'zsh'], description: 'Shell interpreter to use'),
        booleanParam(name: 'SKIP_BUILD', defaultValue: false, description: 'Skip build stage'),
        booleanParam(name: 'SKIP_TESTS', defaultValue: false, description: 'Skip test stage'),
        booleanParam(name: 'SKIP_DEPLOYMENT', defaultValue: false, description: 'Skip deployment stage'),
        booleanParam(name: 'FAIL_ON_TEST_ERROR', defaultValue: true, description: 'Fail pipeline if tests fail'),
        booleanParam(name: 'PARALLEL_EXECUTION', defaultValue: false, description: 'Run build and test in parallel'),
        string(name: 'WORKING_DIRECTORY', defaultValue: '.', description: 'Working directory for commands'),
        string(name: 'BUILD_TIMEOUT', defaultValue: '30', description: 'Build timeout in minutes'),
        string(name: 'TEST_TIMEOUT', defaultValue: '30', description: 'Test timeout in minutes'),
        string(name: 'DEPLOY_TIMEOUT', defaultValue: '30', description: 'Deployment timeout in minutes'),
        text(name: 'ENVIRONMENT_VARIABLES', defaultValue: '', description: 'Environment variables (KEY=VALUE, one per line)'),
        string(name: 'ARTIFACT_PATH', defaultValue: '', description: 'Path to artifacts to archive (optional)'),
        booleanParam(name: 'VERBOSE_OUTPUT', defaultValue: true, description: 'Show verbose command output'),
        text(name: 'CUSTOM_CLEANUP_SCRIPT', defaultValue: '', description: 'Custom cleanup script to run in post stage')
    ])
])

pipeline {
    agent any
    
    environment {
        SHELL_INTERPRETER = "${params.SHELL_TYPE}"
        WORKSPACE_DIR = "${params.WORKING_DIRECTORY}"
    }
    
    stages {
        stage('Initialize') {
            steps {
                script {
                    echo "=== Pipeline Configuration ==="
                    echo "Build Command: ${params.BUILD_COMMAND}"
                    echo "Test Command: ${params.TEST_COMMAND}"
                    echo "Deployment Command: ${params.DEPLOYMENT_COMMAND}"
                    echo "Shell Type: ${params.SHELL_TYPE}"
                    echo "Working Directory: ${params.WORKING_DIRECTORY}"
                    echo "Skip Build: ${params.SKIP_BUILD}"
                    echo "Skip Tests: ${params.SKIP_TESTS}"
                    echo "Skip Deployment: ${params.SKIP_DEPLOYMENT}"
                    echo "=============================="
                    
                    if (params.ENVIRONMENT_VARIABLES?.trim()) {
                        echo "Setting custom environment variables..."
                        params.ENVIRONMENT_VARIABLES.split('\n').each { line ->
                            if (line.trim() && line.contains('=')) {
                                def parts = line.split('=', 2)
                                env."${parts[0].trim()}" = parts[1].trim()
                                if (params.VERBOSE_OUTPUT) {
                                    echo "Set ${parts[0].trim()}=${parts[1].trim()}"
                                }
                            }
                        }
                    }
                }
            }
        }
        
        stage('Pre-Build') {
            when {
                expression { !params.SKIP_BUILD && params.PRE_BUILD_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Pre-Build Script ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeShellCommand(params.PRE_BUILD_SCRIPT, params.BUILD_TIMEOUT)
                    }
                }
            }
        }
        
        stage('Build') {
            when {
                expression { !params.SKIP_BUILD }
            }
            steps {
                script {
                    echo "=== Executing Build Command ==="
                    dir(params.WORKING_DIRECTORY) {
                        timeout(time: params.BUILD_TIMEOUT.toInteger(), unit: 'MINUTES') {
                            executeShellCommand(params.BUILD_COMMAND, params.BUILD_TIMEOUT)
                        }
                    }
                }
            }
        }
        
        stage('Post-Build') {
            when {
                expression { !params.SKIP_BUILD && params.POST_BUILD_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Post-Build Script ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeShellCommand(params.POST_BUILD_SCRIPT, params.BUILD_TIMEOUT)
                    }
                }
            }
        }
        
        stage('Pre-Test') {
            when {
                expression { !params.SKIP_TESTS && params.PRE_TEST_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Pre-Test Script ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeShellCommand(params.PRE_TEST_SCRIPT, params.TEST_TIMEOUT)
                    }
                }
            }
        }
        
        stage('Test') {
            when {
                expression { !params.SKIP_TESTS }
            }
            steps {
                script {
                    echo "=== Executing Test Command ==="
                    dir(params.WORKING_DIRECTORY) {
                        timeout(time: params.TEST_TIMEOUT.toInteger(), unit: 'MINUTES') {
                            if (params.FAIL_ON_TEST_ERROR) {
                                executeShellCommand(params.TEST_COMMAND, params.TEST_TIMEOUT)
                            } else {
                                try {
                                    executeShellCommand(params.TEST_COMMAND, params.TEST_TIMEOUT)
                                } catch (Exception e) {
                                    echo "Test failed but continuing pipeline: ${e.message}"
                                    currentBuild.result = 'UNSTABLE'
                                }
                            }
                        }
                    }
                }
            }
        }
        
        stage('Post-Test') {
            when {
                expression { !params.SKIP_TESTS && params.POST_TEST_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Post-Test Script ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeShellCommand(params.POST_TEST_SCRIPT, params.TEST_TIMEOUT)
                    }
                }
            }
        }
        
        stage('Archive Artifacts') {
            when {
                expression { params.ARTIFACT_PATH?.trim() }
            }
            steps {
                script {
                    echo "=== Archiving Artifacts ==="
                    try {
                        archiveArtifacts artifacts: params.ARTIFACT_PATH, allowEmptyArchive: true
                    } catch (Exception e) {
                        echo "Failed to archive artifacts: ${e.message}"
                    }
                }
            }
        }
        
        stage('Pre-Deploy') {
            when {
                expression { !params.SKIP_DEPLOYMENT && params.PRE_DEPLOY_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Pre-Deploy Script ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeShellCommand(params.PRE_DEPLOY_SCRIPT, params.DEPLOY_TIMEOUT)
                    }
                }
            }
        }
        
        stage('Deploy') {
            when {
                expression { !params.SKIP_DEPLOYMENT }
            }
            steps {
                script {
                    echo "=== Executing Deployment Command ==="
                    dir(params.WORKING_DIRECTORY) {
                        timeout(time: params.DEPLOY_TIMEOUT.toInteger(), unit: 'MINUTES') {
                            executeShellCommand(params.DEPLOYMENT_COMMAND, params.DEPLOY_TIMEOUT)
                        }
                    }
                }
            }
        }
        
        stage('Post-Deploy') {
            when {
                expression { !params.SKIP_DEPLOYMENT && params.POST_DEPLOY_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Post-Deploy Script ==="
                    dir(params.WORKING_DIRECTORY) {
                        executeShellCommand(params.POST_DEPLOY_SCRIPT, params.DEPLOY_TIMEOUT)
                    }
                }
            }
        }
    }
    
    post {
        always {
            script {
                echo "=== Pipeline Execution Summary ==="
                echo "Result: ${currentBuild.result ?: 'SUCCESS'}"
                echo "Duration: ${currentBuild.durationString}"
                
                if (params.CUSTOM_CLEANUP_SCRIPT?.trim()) {
                    echo "=== Executing Custom Cleanup Script ==="
                    try {
                        dir(params.WORKING_DIRECTORY) {
                            executeShellCommand(params.CUSTOM_CLEANUP_SCRIPT, '10')
                        }
                    } catch (Exception e) {
                        echo "Cleanup script failed: ${e.message}"
                    }
                }
            }
        }
        success {
            echo "Pipeline completed successfully!"
        }
        failure {
            echo "Pipeline failed!"
        }
        unstable {
            echo "Pipeline completed with warnings!"
        }
    }
}

def executeShellCommand(String command, String timeout) {
    if (!command?.trim()) {
        echo "No command to execute"
        return
    }
    
    def shellCmd = params.SHELL_TYPE ?: 'sh'
    
    if (params.VERBOSE_OUTPUT) {
        echo "Executing command with ${shellCmd}:"
        echo "---"
        echo command
        echo "---"
    }
    
    if (isUnix()) {
        sh """
            set +x
            ${params.VERBOSE_OUTPUT ? 'set -x' : ''}
            ${command}
        """
    } else {
        bat """
            @echo ${params.VERBOSE_OUTPUT ? 'on' : 'off'}
            ${command}
        """
    }
}